      {
        "question": "What is a sprite in game development?",
        "options": [
          "A type of sound effect",
          "A 2D image or animation",
          "A game character's AI",
          "A level design tool"
        ],
        "correctAnswer": 1,
        "explanation": "A sprite refers to a 2D image or animation used in games."
      },
      {
        "question": "What does 'collision detection' refer to?",
        "options": [
          "Tracking player scores",
          "Determining if two objects intersect",
          "Loading game assets",
          "Saving game progress"
        ],
        "correctAnswer": 1,
        "explanation": "Collision detection is the process of determining if two game objects intersect or collide."
